-- Seed: one usage-focused multiple-choice question per AI tool.
-- Generated by scripts/build_ai_tools_seed.py — do not edit by hand.
--
-- We look up each ai_tools.id by slug so the content_key matches what
-- the app passes to MarkDoneButton (the row's UUID, as text).

insert into content_questions (content_type, content_key, question, options, correct_index)
select 'ai_tool', t.id::text, q.question, q.options, q.correct_index
from ai_tools t
join (
  values
    ('claude', 'You need to read a 100-page deal contract and surface the riskiest clauses for legal. Which Claude strength is doing the heavy lifting?', array['Real-time image generation from the contract pages','Long-context document analysis with nuanced reasoning','Live web search across legal databases','Voice transcription of the negotiation calls'], 1),
    ('chatgpt', 'What''s the right ChatGPT feature to keep your brand voice consistent across many separate chats?', array['Re-paste the brand guide into every new conversation','Use Custom Instructions or a Project so context auto-loads','Train a private fine-tuned model from the dashboard','Switch to a different model for each chat'], 1),
    ('perplexity', 'When would you reach for Perplexity instead of a generic chatbot?', array['When you need an answer with cited, verifiable sources','When you want to generate brand photography','When you need to draft legal contracts offline','When you need to render a 3D product mockup'], 0),
    ('gemini', 'Which workflow plays to Gemini''s strengths inside Google Workspace?', array['Compiling iOS apps in the cloud','Replacing your CRM database','Drafting in Docs, summarising Gmail threads, and analysing Sheets','Hosting podcasts as audio files'], 2),
    ('notebooklm', 'What is NotebookLM uniquely good at?', array['Generating product photos from a brief','Grounding answers in only the documents you upload, with citations','Running paid ad campaigns end-to-end','Building Notion databases for you'], 1),
