    ('gamma', 'What''s Gamma best for?', array['Running webinar broadcasts','Drafting decks, docs and webpages from a prompt with on-brand styling baked in','Editing podcasts','Sending bulk SMS'], 1),
    ('chatbase', 'Where would you deploy Chatbase?', array['As a CI/CD runner for your repo','As a custom AI chatbot trained on your docs/site, embedded for support or lead-gen','As a video editor for shorts','As a payment processor'], 1),
