    ('higgsfield', 'What does Higgsfield specialise in?', array['Cinematic AI video with strong camera control (motion, lenses, character consistency)','Bookkeeping','PDF parsing','Slack notifications'], 0),
    ('veo', 'What is Google''s Veo built for?', array['Compressing files in the cloud','High-fidelity, longer-form generative video with strong prompt adherence and audio','Editing spreadsheets','Reading scientific papers'], 1),
