    ('apollo', 'What is Apollo.io for?', array['A B2B sales platform — find prospects from a giant contact database and run multi-channel outbound sequences','Encoding video for OTT','Building dashboards from CSV files','A drawing app for whiteboards'], 0),
    ('clay', 'What does Clay let GTM teams do that a CRM doesn''t?', array['Enrich any list of accounts/contacts from 100+ sources and run AI research per row at scale','Edit marketing videos','Replace your data warehouse','Host a customer-facing chatbot'], 0),
    ('apify', 'What is Apify?', array['A music generator','A platform of pre-built and custom web scrapers (Actors) for extracting structured data at scale','A CRM','A WYSIWYG site builder'], 1),
    ('vs-code', 'Why does VS Code still belong on a 2026 AI-tools list?', array['It bundles a CRM','It''s the default host for Copilot, Continue, Cursor-style extensions and remote AI assistants — the IDE most AI dev tooling targets first','It only runs on Linux servers','It comes with a built-in design tool'], 1),
    ('claude-code', 'What is Claude Code, specifically?', array['A web-based no-code app builder','Anthropic''s terminal-native agentic coding CLI that can read your repo, run commands and write code across many files','A SaaS analytics tool','A video editor'], 1),
    ('awesome-claude-plugins', 'What is awesome-claude-plugins?', array['A curated community list of plugins / skills that extend Claude Code and Claude Cowork','Anthropic''s billing dashboard','A model-training framework','A design system'], 0),
    ('skills-sh', 'What does skills.sh distribute?', array['Stock video clips','Installable, packaged skills (pre-built workflows) you can drop into Claude / Claude Code','Cold-email templates','Voiceover talent'], 1)
) as q(slug, question, options, correct_index)
on t.slug = q.slug;
